const express = require('express');
const { Configuration, OpenAIApi } = require('openai');
const vm = require('vm');

const app = express();
app.use(express.json());

const openai = new OpenAIApi(new Configuration({
  apiKey: process.env.OPENAI_API_KEY,
}));

app.post('/generate-code', async (req, res) => {
  try {
    const userPrompt = req.body.prompt;
    const response = await openai.createCompletion({
      model: 'text-davinci-003',
      prompt: `Generate secure JavaScript code for: ${userPrompt}`,
      max_tokens: 150,
    });

    const generatedCode = response.data.choices[0].text.trim();

    // Securely execute the generated code
    const sandbox = {};
    const script = new vm.Script(generatedCode);
    const context = new vm.createContext(sandbox);
    script.runInContext(context, { timeout: 1000 });

    res.json({ success: true, code: generatedCode, result: sandbox.result });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});